import { BASE_URL } from "../constants"
import { UserEntity } from "../entities/UserEntity"
import FetchUtils from "../utils/fetch"

class UserService {
    static async GetAllUser(): Promise<UserEntity[]> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/users`)

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        const data: UserEntity[] = []
        for (let i = 0; i < resp.data.length; i++) {
            data.push(new UserEntity({
                users_id: resp.data[i].users_id,
                username: resp.data[i].username,
                grup: resp.data[i].grup,
            }))
        }

        return data
    }

    static async GetAllGrup(): Promise<{ grup_id: number, grup: string }[]> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/users/grup`)

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        const data: { grup_id: number, grup: string }[] = []
        for (let i = 0; i < resp.data.length; i++) {
            data.push({ grup_id: resp.data[i].grup_id, grup: resp.data[i].grup })
        }

        return data
    }

    static async AddUser(data: { grup_id: number, username: string }): Promise<{ message: string }> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/users`,
            {
                method: 'POST',
                body: JSON.stringify({ ...data }),
                headers: { "Content-Type": "application/json" }
            }
        )

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        return resp
    }

    static async UpdateUser(user: UserEntity, fields: { grup_id?: number, username?: string }): Promise<{ message: string }> {
        if (fields.grup_id == 1) {
            fields = {
                username: fields.username,
                grup_id: fields.grup_id
            }
        }

        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/users`,
            {
                method: 'PATCH',
                body: JSON.stringify({ users_id: user.users_id, fields }),
                headers: { "Content-Type": "application/json" }
            }
        )

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        return resp
    }

    static async DeleteUser(id_data: number): Promise<{ message: string }> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/users`,
            {
                method: 'DELETE',
                body: JSON.stringify({ users_id: id_data }),
                headers: { "Content-Type": "application/json" }
            }
        )

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        return resp
    }
}

export { UserService }