class UserEntity {
    users_id: number;
    username: string;
    grup: string;

    constructor(object: UserEntity) {
        this.users_id = object.users_id;
        this.username = object.username;
        this.grup = object.grup;
    }
}

class UserContextEntity {
    username: string;
    rolename: string;

    constructor(object: UserContextEntity) {
        this.username = object.username;
        this.rolename = object.rolename;
    }
}

class FormUserEntity {
    grup_id?: number;
    username?: string;
    grup?: string;

    constructor(object: FormUserEntity) {
        this.grup_id = object.grup_id;
        this.username = object.username;
        this.grup = object.grup;
    }
}

export { UserEntity, FormUserEntity, UserContextEntity };