import { useState, useEffect, useContext, useRef } from "react"
import AppContext from "../../context"
import css from "./Master.module.css"
import Card from "../../components/Card/Card"
import backgroundCard from "../../assets/images/backgroundCardBlue.jpg"
import Popup from "../../components/Popup/Popup"
import { FaEdit } from "react-icons/fa"
import { UserService } from "../../services/user"
import { FormUserEntity, UserEntity } from "../../entities/UserEntity"
import { PopUpPilihEntity } from "../../components/Popup/PopupPilihEntity"
import PopupPilih from "../../components/Popup/PopupPilih"
import ExcelUtils from "../../utils/excel"
import { AlertEntity } from "../../layouts/Alert/AlertEntity"
import { FaSortDown, FaSortUp } from "react-icons/fa6"
import filterUtils from "../../utils/filter-utils"
import { GrPowerReset } from "react-icons/gr"

export default function MasterUser() {
    // ========================================= GLOBAL CONTEXT =========================================  //
    const context = useContext(AppContext)
    const contextAccessToken = context.contextAccessToken
    const contextShowAlertFunc = context.contextShowAlertFunc
    const contextShowLoadingFunc = context.contextShowLoadingFunc
    const stateShowLoading = context.stateShowLoading
    // ========================================= GLOBAL CONTEXT =========================================  //


    // ========================================= STATE VIEW =========================================  //
    const [tableData, setTableData] = useState<UserEntity[]>([])
    const [tableDataCache, setTableDataCache] = useState<UserEntity[]>([])

    const [selectedData, setSelectedData] = useState<UserEntity | null>(null)
    const [formData, setFormData] = useState<FormUserEntity | null>(null)

    const [showPopup, setShowPopup] = useState(false)
    const [showPopupPilih, setShowPopupPilih] = useState(false)
    const [popUpPilihEntity, setPopUpPilihEntity] = useState<PopUpPilihEntity>()
    const [sortColumnChoosed, setSortColumnChoosed] = useState<keyof UserEntity | null>(null)
    const [sortColumnType, setSortColumnType] = useState<"ascending" | "descending">("ascending")
    const [tableDataFilter, setTableDataFilter] = useState<{ [key: string]: string }>({})

    const textinputRef = useRef<HTMLInputElement | null>(null)
    // ========================================= STATE VIEW =========================================  //

    // ========================================= FUNCTIONS =========================================  //
    // ========================================= FUNCTIONS =========================================  //

    const handleSelectGrup = async () => {
        contextShowLoadingFunc(true)
        setShowPopup(false)

        try {
            const resp = await UserService.GetAllGrup()

            setPopUpPilihEntity(new PopUpPilihEntity({
                popupTitle: 'Select Group',
                tableContent: resp,
                onClick: (row) => {
                    setFormData((prevState: FormUserEntity | null) => {
                        return new FormUserEntity({
                            ...prevState,
                            grup_id: row.grup_id,
                            grup: row.grup
                        })
                    })
                    setShowPopup(true)
                },
                onClose: () => { setShowPopupPilih(false); setShowPopup(true) }
            }))
            setShowPopupPilih(true)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    const handleAddNew = () => {
        setFormData(null)
        setSelectedData(null)
        setShowPopup(true)
    }

    const handlePopupDetail = (row: UserEntity) => {
        setSelectedData(row)
        setFormData(null)
        setShowPopup(true)
    }

    const handleSaveAddAdmin = async () => {
        contextShowLoadingFunc(true)

        try {
            if (formData?.grup_id == null || formData?.username == null) { throw new Error("Please fill in all forms!") }
            const resp = await UserService.AddUser({ grup_id: formData.grup_id, username: formData.username })

            await generateData()
            setSelectedData(null)
            setFormData(null)
            setShowPopup(false)
            contextShowAlertFunc(new AlertEntity({ message: resp.message, level: 1 }))
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    const handleSaveUpdateAdmin = async () => {
        contextShowLoadingFunc(true)

        try {
            if (selectedData == null || formData == null) { throw new Error("Please fill in all forms!") }
            const resp = await UserService.UpdateUser(selectedData, { grup_id: formData.grup_id, username: formData.username })

            await generateData()
            setSelectedData(null)
            setShowPopup(false)
            contextShowAlertFunc(new AlertEntity({ message: resp.message, level: 1 }))
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    const handleDeleteAdmin = async () => {
        return contextShowAlertFunc(new AlertEntity({
            message: `Are you sure you want to delete ${selectedData?.username} ?`,
            onOk: async () => {
                contextShowLoadingFunc(true)

                try {
                    if (selectedData == null) return
                    const resp = await UserService.DeleteUser(selectedData.users_id)

                    await generateData()
                    setSelectedData(null)
                    setShowPopup(false)
                    contextShowAlertFunc(new AlertEntity({ message: resp.message, level: 1 }))
                } catch (error: any) {
                    contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
                } finally {
                    contextShowLoadingFunc(false)
                }
            },
            withCancel: true,
            withOk: true,
            level: 2
        }))
    }

    const handleGenerateExcel = async () => {
        if (tableData.length == 0) { return contextShowAlertFunc(new AlertEntity({ message: "NO DATA!", level: 3 })); }

        const column = ["username", "grup"]
        let values: { [key: string]: string }[] = []
        for (let i = 0; i < tableData.length; i++) {
            values.push({
                username: tableData[i].username,
                grup: tableData[i].grup ?? '',
            })
        }

        ExcelUtils.export(`Master Users List`, column, values)
    }

    const handleSorting = (column: keyof UserEntity | null) => {
        setSortColumnChoosed(column)
        if (sortColumnType === "ascending") {
            setSortColumnType("descending")
        } else {
            setSortColumnType("ascending")
        }
    }

    const handleFilter = async () => {
        contextShowLoadingFunc(true)

        try {
            const resp = tableDataCache
            let table_filtered = resp
                .filter((row) => {
                    return filterUtils.FilterTable(row, tableDataFilter)
                })
            setTableData(table_filtered)
            contextShowLoadingFunc(false)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
            contextShowLoadingFunc(false)
        }
    }

    const generateData = async () => {
        contextShowLoadingFunc(true)

        try {
            const resp = await UserService.GetAllUser()

            setTableData(resp)
            setTableDataCache(resp)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        } finally {
            contextShowLoadingFunc(false)
        }
    }

    const filterTable = (column: keyof UserEntity, columnnName?: string) => {
        return <div>
            <input style={{ fontSize: "12px", marginTop: "0.5dvh", maxWidth: "500px" }} type="text" value={tableDataFilter[column] ?? ""}
                placeholder={`${columnnName ?? column} ...`}
                onChange={(event) => {
                    setTableDataFilter((prev) => {
                        const newData = { ...prev }
                        newData[column] = event.target.value
                        return newData
                    })
                }}
            />
        </div>
    }

    const headerTable = (column: keyof UserEntity, columnName?: string) => {
        return <>
            <div style={{ display: "flex", flexDirection: "row", justifyContent: "center", gap: "3px", whiteSpace: "nowrap", cursor: "pointer" }} onClick={() => handleSorting(column)}>
                <div>{columnName ?? column}</div>
                <div style={{

                    display: "flex", flexDirection: "column", gap: "0", alignItems: "center", justifyItems: "center"
                }}
                >
                    <FaSortUp style={{ color: ((sortColumnChoosed == column && sortColumnType == "descending") ? "var(--secondary-color)" : "silver"), margin: 0, padding: 0, height: '18px' }} />
                    <FaSortDown style={{ color: ((sortColumnChoosed == column && sortColumnType == "ascending") ? "var(--secondary-color)" : "silver"), margin: "-18px", padding: 0, height: '18px' }} />
                </div>
            </div>
        </>
    }

    const handleInputFocus = () => {
        setTimeout(() => {
            textinputRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' })
        }, 300)
    }

    const PopupInputData = (props: {
        label: string,
        type_input: "text" | "number",
        value: string | number,
        required: boolean,
        attribute: keyof FormUserEntity,
        onchange?: (event: React.ChangeEvent<HTMLInputElement>) => void
    }) => {
        const { label, value, required, attribute, onchange, type_input } = props
        return <>
            <div className={css.label}> {label} {required ? <span style={{ color: "red" }}>*</span> : <></>}</div>
            <input className={css.inputedit} type={type_input}
                ref={textinputRef}
                value={value}
                onFocus={handleInputFocus}
                onChange={onchange != null ? onchange : (event) => {
                    setFormData((prev) => {
                        const data = { ...prev }
                        if (attribute === 'grup_id') {
                            data[attribute] = parseInt(event.target.value)
                        } else {
                            data[attribute] = (event.target.value)
                        }
                        return data
                    })
                }}
            />
        </>
    }

    useEffect(() => {
        generateData()
    }, [contextAccessToken])

    useEffect(() => {
        handleFilter()
    }, [tableDataFilter])

    // ========================================= FUNCTIONS =========================================  //
    // ========================================= FUNCTIONS =========================================  //

    return (
        <>
            <div className="container" style={{ display: stateShowLoading ? "none" : "flex", backgroundColor: "transparent" }}>

                <div style={{ height: "94dvh", maxHeight: "100vh", display: "flex", flexDirection: "column" }}>

                    {/* Card Header */}
                    <div style={{ flexBasis: "auto" }} className="ordering-card">
                        <Card
                            detailTitle="Master User"
                            detailColor="var(--secondary-color)"
                            backgroundImage={backgroundCard}
                            stateShow={true}
                            detailCard={
                                <>
                                    <div className={css.rowGrid} style={{ alignItems: 'end' }}>
                                        <div>
                                            <div style={{ color: "white", textAlign: "start" }}>Action :</div>
                                            <button className="cardButton" onClick={() => handleAddNew()} >
                                                Add New
                                            </button>
                                        </div>
                                        <div>
                                            <button className="cardButton" onClick={() => handleGenerateExcel()} >
                                                Generate Excel
                                            </button>
                                        </div>
                                        <div>
                                            <button className="cardButton" onClick={() => { setTableDataFilter({}); generateData(); setSortColumnChoosed(null); setSortColumnType("descending") }} >
                                                <GrPowerReset /> &nbsp; Reset Filter
                                            </button>
                                        </div>
                                    </div>
                                </>
                            }
                        />
                    </div>

                    {/* Table */}
                    <div style={{ flex: 1, overflowY: "auto" }} className="ordering-table">
                        <table className="tableclickcell">
                            <thead>
                                <tr>
                                    <th>No</th>
                                    <th>
                                        {headerTable("username", "Username")}
                                        {filterTable("username", "Username")}
                                    </th>
                                    <th>
                                        {headerTable("grup", "Group")}
                                        {filterTable("grup", "Group")}
                                    </th>
                                    <th>Action</th>
                                </tr>
                            </thead>
                            {tableData.length > 0
                                ? <tbody>
                                    {tableData.sort((a, b) => {
                                        if (!sortColumnChoosed) return 0
                                        if (sortColumnType == "ascending") {
                                            return filterUtils.SortingTable(a, b, sortColumnChoosed)
                                        } else {
                                            return filterUtils.SortingTable(b, a, sortColumnChoosed)
                                        }
                                    }).map((row, index) => {
                                        return (
                                            <tr key={index}>
                                                <td>{index + 1}</td>
                                                <td>{row.username}</td>
                                                <td>{row.grup}</td>
                                                <td className="group-pick" onClick={() => { handlePopupDetail(row) }}>
                                                    <FaEdit /> Edit
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                                : <tbody><tr><td colSpan={1000}>No Data Available Yet !</td></tr></tbody>
                            }
                        </table>
                    </div>

                </div>


                {/* Popup Detail */}
                <Popup
                    setShowPopup={setShowPopup}
                    showPopup={showPopup}
                    popupTitle={selectedData == null ? "Add New" : `Edit ${selectedData?.username}`}
                    popupContent={<>
                        <div className={css.form}>
                            <div className={css.containerleftright}>
                                <div className={css.leftposition}>
                                    {PopupInputData({
                                        label: "Username", value: formData?.username ?? selectedData?.username ?? '', type_input: 'text',
                                        attribute: "username", required: true
                                    })}
                                    <div className={css.label}> Role <span style={{ color: "red" }}>*</span></div>
                                    <input className={css.inputedit} type="text" readOnly
                                        value={formData?.grup ?? selectedData?.grup ?? ""}
                                        onClick={handleSelectGrup}
                                    />
                                </div>
                            </div>
                            <div className={css.buttons2}>
                                <div className={css.left}>
                                    <button className="tertiaryButton" onClick={() => { setShowPopup(false) }} >
                                        Close
                                    </button>
                                </div>
                                {selectedData &&
                                    <div className={css.right}>
                                        <button className="secondaryButton" onClick={() => handleDeleteAdmin()}>
                                            Delete
                                        </button>
                                    </div>
                                }
                                <div className={css.right}>
                                    <button className="primaryButton"
                                        onClick={() => { selectedData ? handleSaveUpdateAdmin() : handleSaveAddAdmin() }} >
                                        Save
                                    </button>
                                </div>
                            </div>
                        </div>
                    </>
                    }
                />

                {popUpPilihEntity != null
                    ? <PopupPilih
                        showPopup={showPopupPilih}
                        setShowPopup={setShowPopupPilih}
                        popUpPilihEntity={popUpPilihEntity}
                    />
                    : <></>}


            </div>
        </>
    );
}
